function decodeSlantedCipher(encodedText, rows) {
    let matrix = new Array(rows).fill("");

    let index = 0;
    for(let diagonal = 0; diagonal < 2 * (rows - 1); diagonal++) {
        for(let row = Math.max(0, diagonal - rows + 1); row <= Math.min(diagonal, rows - 1); row++) {
            if(index < encodedText.length) {
                matrix[row] += encodedText[index++];
            }
        }
    }

    return matrix.join("");
}
