public String decodeSlantedCipher(String encodedText, int rows) {
    StringBuilder[] matrix = new StringBuilder[rows];
    for(int i = 0; i < rows; i++) {
        matrix[i] = new StringBuilder("");
    }

    int index = 0;
    for(int diagonal = 0; diagonal < 2 * (rows - 1); diagonal++) {
        for(int row = Math.max(0, diagonal - rows + 1); row <= Math.min(diagonal, rows - 1); row++) {
            if(index < encodedText.length()) {
                matrix[row].append(encodedText.charAt(index++));
            }
        }
    }

    StringBuilder originalText = new StringBuilder();
    for(int i = 0; i < rows; i++) {
        originalText.append(matrix[i]);
    }
    return originalText.toString();
}
```

